import { useState } from "react";
import API from "../services/api";
import { supabase } from "../services/supabaseClient";

export default function Upload() {
  const [file, setFile] = useState(null);
  const [text, setText] = useState("");
  const [summary, setSummary] = useState("");
  const [showSummary, setShowSummary] = useState(false);
  const [loading, setLoading] = useState(false);

  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState("");
  const [asking, setAsking] = useState(false);

  const [docId, setDocId] = useState(null);
  const [userId, setUserId] = useState(null);

  const [papers, setPapers] = useState([]);
  const [loadingRec, setLoadingRec] = useState(false);

  // 🔐 Auth Header
  const getAuthHeader = async () => {
    const { data: { session } } = await supabase.auth.getSession();
    return session ? { Authorization: `Bearer ${session.access_token}` } : {};
  };

  // 📄 Upload
  const handleUpload = async () => {
    if (!file) return alert("Select a file");

    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const formData = new FormData();
      formData.append("file", file);

      const res = await API.post("/upload", formData, {
        headers: {
          ...authHeader,
          "Content-Type": "multipart/form-data"
        }
      });

      setText(res.data.preview);
      setDocId(res.data.doc_id);
      setUserId(res.data.user_id);

      setAnswer("");
      setQuestion("");
      setSummary("");
      setShowSummary(false);
      setPapers([]);

    } catch (err) {
      console.error(err);
      alert("Upload failed ❌");
    } finally {
      setLoading(false);
    }
  };

  // 💬 Q&A
  const askQuestion = async () => {
    if (!question || !docId) return alert("Upload + enter question");

    try {
      setAsking(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/ask", {
        question,
        doc_id: docId,
        user_id: userId
      }, { headers: authHeader });

      setAnswer(res.data.answer);

    } catch (err) {
      console.error(err);
    } finally {
      setAsking(false);
    }
  };

  // 🧠 Summary
  const handleGenerateSummary = async () => {
    try {
      setLoading(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/summarize", { text }, { headers: authHeader });

      setSummary(res.data.summary);
      setShowSummary(true);

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // 🔍 Recommend
  const handleRecommend = async () => {
    try {
      setLoadingRec(true);
      const authHeader = await getAuthHeader();

      const res = await API.post("/recommend", {
        query: text
      }, { headers: authHeader });

      setPapers(res.data.recommendations || []);

    } catch (err) {
      console.error(err);
    } finally {
      setLoadingRec(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-6">

      {/* Upload Card */}
      <div className="bg-white shadow-md rounded-xl p-6">
        <h2 className="text-xl font-semibold mb-4">Upload Research Paper</h2>

        <input
          type="file"
          accept=".pdf"
          onChange={(e) => setFile(e.target.files[0])}
          className="mb-4"
        />

        <button
          onClick={handleUpload}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"
        >
          {loading ? "Processing..." : "Upload & Analyze"}
        </button>
      </div>

      {/* Preview */}
      {text && (
        <div className="mt-6 bg-gray-50 p-4 rounded-lg shadow-sm">
          <h3 className="font-semibold mb-2">Extracted Text</h3>
          <p className="text-sm text-gray-600 max-h-40 overflow-y-auto">
            {text.slice(0, 1000)}...
          </p>
        </div>
      )}

      {/* Buttons */}
      {text && (
        <div className="mt-4 flex gap-3">
          <button onClick={handleGenerateSummary} className="btn">
            🧠 Summarize
          </button>

          <button onClick={handleRecommend} className="btn">
            {loadingRec ? "Finding..." : "🔍 Recommend"}
          </button>
        </div>
      )}

      {/* Summary */}
      {showSummary && (
        <div className="mt-6 bg-blue-50 p-4 rounded-lg">
          <h3 className="font-semibold">Summary</h3>
          <p>{summary}</p>
        </div>
      )}

      {/* Q&A */}
      {text && (
        <div className="mt-6">
          <h3 className="font-semibold mb-2">💬 Ask Question</h3>

          <div className="flex gap-2">
            <input
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              className="border p-2 flex-1 rounded-lg"
              placeholder="Ask something..."
            />

            <button onClick={askQuestion} className="btn">
              {asking ? "Thinking..." : "Ask"}
            </button>
          </div>

          {answer && (
            <div className="mt-4 bg-green-50 p-4 rounded-lg">
              <h4 className="font-semibold">Answer</h4>
              <p>{answer}</p>
            </div>
          )}
        </div>
      )}

      {/* Recommendations */}
      {papers.length > 0 && (
        <div className="mt-6 bg-purple-50 p-4 rounded-lg">
          <h3 className="font-semibold mb-3">📚 Recommended Papers</h3>

          <ul className="space-y-2">
            {papers.map((title, i) => (
              <li key={i} className="bg-white p-3 rounded shadow-sm">
                • {title}
              </li>
            ))}
          </ul>
        </div>
      )}

    </div>
  );
}
